import React, { useState } from 'react';
import './Recruitment.css';

const API = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const PERKS = [
  { icon: '', title: 'Thu nhập đảm bảo ', desc: 'Chiết khấu cạnh tranh 70/30 doanh thu (tài xế/hãng). Ca linh hoạt.' },
  { icon: '', title: 'Điều phối thông minh', desc: 'Websie điều xe tự động, ưu tiên chuyến gần, tránh chờ đợi lâu.' },
  { icon: '', title: 'BHXH đầy đủ', desc: 'Ký hợp đồng lao động chính thức, BHXH + BHYT đầy đủ theo luật.' },
];

export default function Recruitment({ showToast }) {
  const [form, setForm] = useState({ name: '', phone: '', licenseType: '', hasOwnCar: 'Không', experience: '', note: '' });
  const [loading, setLoading] = useState(false);
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async e => {
    e.preventDefault();
    if (!form.name || !form.phone || !form.licenseType) return showToast('Vui lòng điền đầy đủ thông tin bắt buộc', 'error');
    setLoading(true);
    try {
      const res = await fetch(`${API}/api/recruitment`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(form) });
      const data = await res.json();
      showToast(data.message, data.success ? 'success' : 'error');
      if (data.success) setForm({ name: '', phone: '', licenseType: '', hasOwnCar: 'Không', experience: '', note: '' });
    } catch { showToast('Lỗi kết nối. Vui lòng thử lại.', 'error'); }
    finally { setLoading(false); }
  };

  return (
    <section id="recruitment" className="section recruit-section">
      <div className="container">
        <div className="section-label" style={{ color: 'rgba(245,166,35,.9)' }}>Tuyển dụng</div>
        <h2 className="section-title" style={{ color: '#fff' }}>Gia nhập đội ngũ tài xế</h2>
        <p style={{ color: 'rgba(255,255,255,.75)', marginBottom: 48, maxWidth: 520 }}>
          Chúng tôi đang tìm kiếm tài xế chuyên nghiệp, thân thiện. Thu nhập ổn định, môi trường làm việc tốt.
        </p>
        <div className="recruit__inner">
          <div>
            <div className="recruit__perks">
              {PERKS.map((p, i) => (
                <div key={i} className="recruit__perk">
                  <div className="recruit__perk-icon">{p.icon}</div>
                  <div>
                    <div className="recruit__perk-title">{p.title}</div>
                    <div className="recruit__perk-desc">{p.desc}</div>
                  </div>
                </div>
              ))}
            </div>
            <div className="recruit__requirements">
              <h4> Yêu cầu cơ bản</h4>
              <ul>
                <li>✓ Bằng lái B2 trở lên (còn hiệu lực)</li>
                <li>✓ Tuổi 21–55</li>
                <li>✓ Lý lịch tư pháp sạch</li>
                <li>✓ Thông thạo đường Tây Ninh</li>
                <li>✓ Điện thoại thông minh</li>
              </ul>
            </div>
          </div>
          <div className="recruit__form card">
            <h3 style={{ fontFamily: 'var(--font-display)', fontWeight: 700, color: 'var(--navy)', marginBottom: 20 }}>Nộp hồ sơ ngay</h3>
            <form onSubmit={handleSubmit} noValidate>
              <div className="form-row">
                <div className="form-group"><label>Họ tên *</label><input placeholder="Nguyễn Văn B" value={form.name} onChange={e => set('name', e.target.value)} /></div>
                <div className="form-group"><label>Số điện thoại *</label><input type="tel" placeholder="09xx xxx xxx" value={form.phone} onChange={e => set('phone', e.target.value)} /></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Hạng bằng lái *</label><select value={form.licenseType} onChange={e => set('licenseType', e.target.value)}><option value="">-- Chọn --</option><option>B2</option><option>C</option><option>D</option><option>E</option></select></div>
                <div className="form-group"><label>Có xe cá nhân?</label><select value={form.hasOwnCar} onChange={e => set('hasOwnCar', e.target.value)}><option>Không</option><option>Có (4 chỗ)</option><option>Có (7 chỗ)</option></select></div>
              </div>
              <div className="form-group"><label>Kinh nghiệm lái xe</label><input placeholder="VD: 5 năm lái taxi tại TP.HCM" value={form.experience} onChange={e => set('experience', e.target.value)} /></div>
              <div className="form-group"><label>Ghi chú</label><textarea placeholder="Mong muốn ca làm việc, khu vực chạy xe..." value={form.note} onChange={e => set('note', e.target.value)} rows={3} /></div>
              <button type="submit" className="btn btn-primary" style={{ width: '100%', justifyContent: 'center' }} disabled={loading}>
                {loading ? '⏳ Đang gửi...' : ' Nộp hồ sơ'}
              </button>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
}
